function redact(text = '') {
  // Keep customer email and phone visible in support logs; they are operational
  // contact details. Still redact high-risk identifiers that should not sit in
  // general workflow logs.
  return String(text).trim()
    .replace(/\b[STFGM]\d{7}[A-Z]\b/gi, '[redacted-nric-fin]')
    .replace(/\b\d{9,}\b/g, '[redacted-id]');
}

function safeSheetValue(value = '') {
  const text = String(value ?? '');
  if (!text) return '';
  if (/^\+\s*[\d()\-\s]{3,}$/.test(text)) return text;
  return /^[=+\-@]/.test(text) ? "'" + text : text;
}

function normaliseForDedupe(text = '') {
  return redact(text).toLowerCase().replace(/\s+/g, ' ').trim();
}

function hashText(text = '') {
  let hash = 2166136261;
  for (const char of text) {
    hash ^= char.charCodeAt(0);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36);
}

function shortSession(value = '') {
  return String(value || 'session').replace(/[^a-z0-9]/gi, '').slice(0, 8) || 'session';
}

function workflowDateKey(date = new Date()) {
  const formatter = new Intl.DateTimeFormat('en-CA', {
    timeZone: '__SET_WORKFLOW_TIMEZONE__',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
  const parts = Object.fromEntries(formatter.formatToParts(date).map((part) => [part.type, part.value]));
  return '' + parts.year + parts.month + parts.day;
}

function conversationRef(item) {
  const sessionId = item.session_id || item.sessionId || item.chatId || 'unknown_session';
  const suffix = hashText(String(sessionId)).toUpperCase().slice(0, 6);
  return item.conversation_ref || 'TEMPLATE-CONV-' + workflowDateKey() + '-' + suffix;
}

function dedupeKey(item, bucketOffset = 0) {
  const bucketSizeMs = 2 * 60 * 1000;
  const bucket = Math.floor(Date.now() / bucketSizeMs) + bucketOffset;
  const sessionId = item.session_id || item.sessionId || item.chatId || 'unknown_session';
  const messageHash = hashText(normaliseForDedupe(item.message)).toUpperCase();
  return 'TEMPLATE-DEDUP-' + shortSession(sessionId) + '-' + messageHash + '-' + bucket;
}

return items.map((item) => {
  const userMessageRedacted = redact(item.json.message);
  const conversationReference = conversationRef(item.json);
  const dedupe = dedupeKey(item.json);
  const previousDedupe = dedupeKey(item.json, -1);

  return {
    json: {
      ...item.json,
      user_message_redacted: userMessageRedacted,
      conversation_ref: conversationReference,
      dedupe_key: dedupe,
      dedupe_key_previous: previousDedupe,
      sheet_conversation_ref: safeSheetValue(conversationReference),
      sheet_channel: safeSheetValue(item.json.channel),
      sheet_customer_name: safeSheetValue(item.json.customer_name),
      sheet_customer_email: safeSheetValue(item.json.customer_email),
      sheet_customer_phone: safeSheetValue(item.json.customer_phone),
      sheet_user_message_redacted: safeSheetValue(userMessageRedacted),
      sheet_execution_id: safeSheetValue(item.json.execution_id),
      sheet_message_id: safeSheetValue(item.json.message_id),
      sheet_session_id: safeSheetValue(item.json.session_id),
      sheet_dedupe_key: safeSheetValue(dedupe),
      sheet_timestamp: safeSheetValue(item.json.timestamp),
    },
  };
});

const item = $input.first();
const input = item && item.json && typeof item.json === 'object' ? item.json : {};

function firstNodeJson(name) {
  try {
    const previous = $(name).first();
    return previous && previous.json && typeof previous.json === 'object' ? previous.json : {};
  } catch (error) {
    return {};
  }
}

function objectValue(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function cleanJsonText(value) {
  let text = String(value || '').trim();
  const fence = String.fromCharCode(96).repeat(3);
  if (text.startsWith(fence)) {
    text = text.slice(fence.length).trim();
    if (text.toLowerCase().startsWith('json')) text = text.slice(4).trim();
    if (text.endsWith(fence)) text = text.slice(0, -fence.length).trim();
  }
  return text;
}

function parseStructured(value) {
  if (value && typeof value === 'object') return objectValue(value);
  const text = cleanJsonText(value);
  if (!text) return {};

  try {
    return objectValue(JSON.parse(text));
  } catch (error) {
    const start = text.indexOf('{');
    const end = text.lastIndexOf('}');
    if (start !== -1 && end > start) {
      return objectValue(JSON.parse(text.slice(start, end + 1)));
    }
    throw error;
  }
}

function text(value) {
  return String(value ?? '').trim();
}

function bool(value) {
  if (typeof value === 'boolean') return value;
  return ['true', '1', 'yes'].includes(text(value).toLowerCase());
}

function list(value) {
  if (Array.isArray(value)) return value.map(text).filter(Boolean);
  const current = text(value);
  return current ? [current] : [];
}

function safeSheetValue(value = '') {
  const current = text(value);
  if (!current) return '';
  if (/^\+\s*[\d()\-\s]{3,}$/.test(current)) return current;
  return /^[=+\-@]/.test(current) ? "'" + current : current;
}

function stableSuffix(...values) {
  const source = values.map(text).find(Boolean) || String(Date.now());
  return source.replace(/[^a-z0-9]/gi, '').slice(-16) || String(Date.now());
}

function workflowTimestamp() {
  try {
    const formatter = new Intl.DateTimeFormat('sv-SE', {
      timeZone: '__SET_WORKFLOW_TIMEZONE__',
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: false,
    });
    return formatter.format(new Date()).replace(',', '') + ' __SET_WORKFLOW_TIMEZONE_LABEL__';
  } catch (error) {
    return new Date().toISOString();
  }
}

const context = firstNodeJson('Restore Processing Context');
const structured = parseStructured(input.output ?? input.response ?? input.text ?? input.message ?? input);
const payload = objectValue(structured.output ?? structured.response ?? structured.result ?? structured);
const lead = objectValue(payload.lead);
const ticket = objectValue(payload.ticket);
const booking = objectValue(payload.booking);
const retrieval = objectValue(payload.retrieval_summary);

const confidence = Math.max(0, Math.min(1, Number(payload.confidence ?? 0) || 0));
const intent = text(payload.intent || 'unknown').toLowerCase() || 'unknown';
const missingFields = list(payload.missing_fields);
const sourceTitles = list(retrieval.source_titles).join(', ');
const sourceFileIds = list(retrieval.source_file_ids).join(', ');
const completedAt = workflowTimestamp();

const ticketRequired = bool(payload.ticket_required);
const leadCaptured = bool(payload.lead_captured);
const bookingRequested = bool(payload.booking_requested);
const ticketHasContact = Boolean(text(ticket.name) || text(ticket.email) || text(ticket.phone) || text(context.customer_name) || text(context.customer_email) || text(context.customer_phone));
const ticketHasDetails = Boolean(text(ticket.summary) || text(ticket.details) || text(payload.reply));
const ticketReady = ticketRequired && ticketHasContact && ticketHasDetails;
const leadReady = leadCaptured || bookingRequested;
const unansweredRequired = intent === 'unknown' || confidence < 0.55 || (!bool(retrieval.used_kb) && !leadReady && !ticketReady);
const incompleteTicketFollowup = ticketRequired && !ticketReady;

const leadId = leadReady ? 'TEMPLATE-LEAD-' + stableSuffix(context.conversation_ref, context.message_id, context.execution_id) : '';
const ticketId = ticketRequired ? 'TEMPLATE-TICKET-' + stableSuffix(context.conversation_ref, context.message_id, context.execution_id) : '';
const unansweredId = unansweredRequired ? 'TEMPLATE-UNANSWERED-' + stableSuffix(context.conversation_ref, context.message_id, context.execution_id) : '';
const conversationRef = text(context.conversation_ref) || text(context.message_id) || stableSuffix(context.session_id, context.execution_id);
const reply = text(payload.reply) || 'I could not produce a complete answer. I will route this to the team for follow-up.';

const output = {
  ...context,
  ...payload,
  reply,
  intent,
  confidence,
  needs_escalation: bool(payload.needs_escalation),
  needs_human_followup: bool(payload.needs_human_followup),
  lead_captured: leadCaptured,
  ticket_required: ticketRequired,
  booking_requested: bookingRequested,
  missing_fields: missingFields,
  missing_fields_text: missingFields.join(', '),
  lead,
  ticket,
  booking,
  retrieval_summary: retrieval,
  source_titles: sourceTitles,
  source_file_ids: sourceFileIds,
  ticket_ready: ticketReady,
  incomplete_ticket_followup: incompleteTicketFollowup,
  unanswered_required: unansweredRequired,
  unanswered_reason: unansweredRequired ? (intent === 'unknown' ? 'unknown_intent' : 'low_confidence_or_missing_kb') : '',
  conversation_ref: conversationRef,
  completed_at: completedAt,
  lead_id: leadId,
  ticket_id: ticketId,
  unanswered_id: unansweredId,
};

return [{
  json: {
    ...output,
    sheet_conversation_ref: safeSheetValue(output.conversation_ref),
    sheet_channel: safeSheetValue(output.channel),
    sheet_customer_name: safeSheetValue(output.customer_name),
    sheet_customer_email: safeSheetValue(output.customer_email),
    sheet_customer_phone: safeSheetValue(output.customer_phone),
    sheet_user_message_redacted: safeSheetValue(output.user_message_redacted),
    sheet_reply: safeSheetValue(output.reply),
    sheet_intent: safeSheetValue(output.intent),
    sheet_source_titles: safeSheetValue(output.source_titles),
    sheet_source_file_ids: safeSheetValue(output.source_file_ids),
    sheet_execution_id: safeSheetValue(output.execution_id),
    sheet_timestamp: safeSheetValue(output.timestamp),
    sheet_completed_at: safeSheetValue(output.completed_at),
    sheet_dedupe_key: safeSheetValue(output.dedupe_key),
    sheet_message_id: safeSheetValue(output.message_id),
    sheet_session_id: safeSheetValue(output.session_id),
    sheet_lead_id: safeSheetValue(output.lead_id),
    sheet_ticket_id: safeSheetValue(output.ticket_id),
    sheet_unanswered_id: safeSheetValue(output.unanswered_id),
  },
}];

const debounceWindowMs = 20 * 1000;
const now = Date.now();
const current = $('Redact PII for Logs').first().json || {};

function safeSheetValue(value = '') {
  const text = String(value ?? '');
  if (!text) return '';
  if (/^\+\s*[\d()\-\s]{3,}$/.test(text)) return text;
  return /^[=+\-@]/.test(text) ? "'" + text : text;
}

function parseWorkflowTimestamp(value) {
  const parsed = Date.parse(value);
  if (Number.isFinite(parsed)) return parsed;
  const match = String(value || '').trim().match(/^(\d{4})-(\d{2})-(\d{2}) (\d{2}):(\d{2}):(\d{2})(?:\s+\S+)?$/);
  if (!match) return NaN;
  const [, year, month, day, hour, minute, second] = match.map(Number);
  return Date.UTC(year, month - 1, day, hour, minute, second);
}

function rowTime(row) {
  const value = row.created_at || row.timestamp || current.timestamp || '';
  const workflowParsed = parseWorkflowTimestamp(value);
  return Number.isFinite(workflowParsed) ? workflowParsed : 0;
}

function meaningful(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  if (/^(n\/a|na|none|null|unknown|__SET_BUILD_INTERNAL_ERROR_CONTEXT_EXECUTION_URL__|pending|pending_ai_response|queued_for_ai_response)$/i.test(text)) return '';
  return text;
}

function messageText(row) {
  return meaningful(row.message) || meaningful(row.user_message_redacted);
}

function uniqueByMessageId(rows) {
  const byId = new Map();
  for (const row of rows) {
    const key = String(row.message_id || '').trim();
    if (!key) continue;
    byId.set(key, row);
  }
  return [...byId.values()];
}

function executionOrder(row) {
  const parsed = Number(String(row.execution_id || '').replace(/[^0-9]/g, ''));
  return Number.isFinite(parsed) ? parsed : 0;
}

function withSheetFields(row) {
  return {
    ...row,
    sheet_conversation_ref: safeSheetValue(row.conversation_ref),
    sheet_channel: safeSheetValue(row.channel),
    sheet_customer_name: safeSheetValue(row.customer_name),
    sheet_customer_email: safeSheetValue(row.customer_email),
    sheet_customer_phone: safeSheetValue(row.customer_phone),
    sheet_user_message_redacted: safeSheetValue(row.user_message_redacted),
    sheet_execution_id: safeSheetValue(row.execution_id),
    sheet_message_id: safeSheetValue(row.message_id),
    sheet_session_id: safeSheetValue(row.session_id),
    sheet_dedupe_key: safeSheetValue(row.dedupe_key),
    sheet_timestamp: safeSheetValue(row.timestamp),
  };
}

const currentTime = rowTime(current) || now;
const sheetRows = items.map((item) => item.json || {});
const currentRow = { ...current, status: 'queued' };
const rows = uniqueByMessageId([...sheetRows, currentRow])
  .filter((row) => String(row.session_id || '') === String(current.session_id || ''))
  .map((row) => ({ ...row, _row_time: rowTime(row) || currentTime }))
  .filter((row) => Math.abs(row._row_time - currentTime) <= debounceWindowMs)
  .filter((row) => ['queued', 'merged', 'processing'].includes(String(row.status || '').toLowerCase()))
  .sort((a, b) =>
    (a._row_time - b._row_time) ||
    (executionOrder(a) - executionOrder(b)) ||
    String(a.message_id || '').localeCompare(String(b.message_id || ''))
  );

const latest = rows[rows.length - 1] || currentRow;
if (String(latest.message_id || '') !== String(current.message_id || '')) {
  return [{
    json: withSheetFields({
      ...current,
      debounce_superseded: 'true',
      debounce_latest_message_id: latest.message_id || '',
      debounce_batch_count: rows.length,
    }),
  }];
}

const batchRows = rows.length ? rows : [currentRow];
const mergedTexts = batchRows
  .map((row, index) => {
    const text = messageText(row);
    return text ? String(index + 1) + '. ' + text : '';
  })
  .filter(Boolean);

const mergedMessage = mergedTexts.length > 1
  ? 'The customer sent these rapid messages in order. Treat them as one customer turn:\n\n' + mergedTexts.join('\n')
  : (meaningful(current.message) || meaningful(current.user_message_redacted));
const mergedUserMessage = mergedTexts.length > 1 ? mergedTexts.join('\n') : current.user_message_redacted;

return [{
  json: withSheetFields({
    ...current,
    message: mergedMessage,
    user_message_redacted: mergedUserMessage,
    debounce_superseded: 'false',
    debounce_batch_count: batchRows.length,
    merged_message_ids: batchRows.map((row) => row.message_id).filter(Boolean).join(', '),
  }),
}];

const MAX_TRANSCRIPT_ROWS = 12;
const MAX_TRANSCRIPT_CHARS = 6000;
const TRUNCATED_MARKER = '[Transcript truncated]';

function escapeHtml(value = '') {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function safeSheetValue(value = '') {
  const text = String(value ?? '');
  if (!text) return '';
  if (/^\+\s*[\d()\-\s]{3,}$/.test(text)) return text;
  return /^[=+\-@]/.test(text) ? "'" + text : text;
}

function meaningful(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  if (/^(n\/a|na|none|null|unknown|__SET_BUILD_INTERNAL_ERROR_CONTEXT_EXECUTION_URL__|not provided|pending)$/i.test(text)) return '';
  return text;
}

function firstMeaningful(...values) {
  for (const value of values) {
    const text = meaningful(value);
    if (text) return text;
  }
  return '';
}

function safeText(value, fallback = '__SET_BUILD_INTERNAL_ERROR_CONTEXT_EXECUTION_URL__') {
  return escapeHtml(firstMeaningful(value, fallback));
}

function safeSubjectText(value, fallback = '__SET_BUILD_INTERNAL_ERROR_CONTEXT_EXECUTION_URL__', maxLength = 100) {
  const text = firstMeaningful(value, fallback)
    .replace(/[\u0000-\u001f\u007f]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  const safe = text || fallback;
  return safe.length > maxLength ? safe.slice(0, maxLength - 3).trimEnd() + '...' : safe;
}

function boolText(value) {
  return String(value).toLowerCase() === 'true' ? 'Yes' : 'No';
}

function rowTime(row) {
  return meaningful(row.created_at) || meaningful(row.completed_at) || meaningful(row.timestamp) || '';
}

function rowTranscriptText(row, displayIndex) {
  const when = rowTime(row) || 'time___SET_BUILD_INTERNAL_ERROR_CONTEXT_EXECUTION_URL__';
  const customerMessage = meaningful(row.user_message_redacted) || meaningful(row.message) || '';
  const botReply = meaningful(row.bot_reply) || meaningful(row.reply) || '';
  const intent = meaningful(row.intent);

  return [
    '#' + displayIndex + ' - ' + when + (intent ? ' - ' + intent : ''),
    customerMessage ? 'Customer: ' + customerMessage : '',
    botReply ? 'Bot: ' + botReply : '',
  ].filter(Boolean).join('\n');
}

function transcriptEntry(row, displayIndex, text) {
  const when = rowTime(row) || 'time___SET_BUILD_INTERNAL_ERROR_CONTEXT_EXECUTION_URL__';
  const customerMessage = meaningful(row.user_message_redacted) || meaningful(row.message) || '';
  const botReply = meaningful(row.bot_reply) || meaningful(row.reply) || '';
  const intent = meaningful(row.intent);
  return {
    displayIndex,
    text,
    html: [
      '<div style="border-left:3px solid #d9e2ec;padding:8px 0 8px 12px;margin:10px 0;">',
      '<p style="margin:0 0 4px 0;color:#52606d;"><strong>#' + displayIndex + '</strong> - ' + escapeHtml(when) + (intent ? ' - ' + escapeHtml(intent) : '') + '</p>',
      customerMessage ? '<p style="margin:0 0 6px 0;"><strong>Customer:</strong> ' + escapeHtml(customerMessage) + '</p>' : '',
      botReply ? '<p style="margin:0;"><strong>Bot:</strong> ' + escapeHtml(botReply) + '</p>' : '',
      '</div>',
    ].join(''),
  };
}

const original = $('Parse Strict JSON Response').first().json || {};
const rows = items
  .map((item) => item.json || {})
  .filter((row) => String(row.session_id || '') === String(original.session_id || ''))
  .sort((a, b) => String(rowTime(a)).localeCompare(String(rowTime(b))));

const transcriptSourceRows = rows.length ? rows : [original];
const newestRows = transcriptSourceRows.slice(-MAX_TRANSCRIPT_ROWS);
const displayOffset = transcriptSourceRows.length - newestRows.length;
let remainingChars = MAX_TRANSCRIPT_CHARS;
let charTruncated = false;
const selectedEntries = [];

for (let index = newestRows.length - 1; index >= 0; index -= 1) {
  const row = newestRows[index];
  const displayIndex = displayOffset + index + 1;
  let text = rowTranscriptText(row, displayIndex);
  const separatorCost = selectedEntries.length ? 2 : 0;
  if (text.length + separatorCost > remainingChars) {
    charTruncated = true;
    const allowed = Math.max(0, remainingChars - separatorCost);
    if (allowed > 80 || selectedEntries.length === 0) {
      text = text.slice(0, Math.max(0, allowed)).trimEnd();
      selectedEntries.unshift(transcriptEntry(row, displayIndex, text));
    }
    break;
  }
  remainingChars -= text.length + separatorCost;
  selectedEntries.unshift(transcriptEntry(row, displayIndex, text));
}

const rowTruncated = transcriptSourceRows.length > newestRows.length;
const transcriptTruncated = rowTruncated || charTruncated || selectedEntries.length < transcriptSourceRows.length;
const transcriptText = selectedEntries.map((entry) => entry.text).join('\n\n') || 'No previous conversation rows found for this session.';
const transcriptHtml = selectedEntries.map((entry) => entry.html).join('') || '<p>No previous conversation rows found for this session.</p>';
const truncationText = transcriptTruncated ? '\n\n' + TRUNCATED_MARKER : '';
const truncationHtml = transcriptTruncated ? '<p><em>' + escapeHtml(TRUNCATED_MARKER) + '</em></p>' : '';

const conversationRef = firstMeaningful(original.conversation_ref, original.ticket_id, original.lead_id, original.message_id);
const caseReference = firstMeaningful(original.ticket_id, original.lead_id, original.unanswered_id, original.message_id);
const lead = original.lead || {};
const ticket = original.ticket || {};
const booking = original.booking || {};

const customerName = firstMeaningful(original.customer_name, lead.name, ticket.name);
const customerEmail = firstMeaningful(original.customer_email, lead.email, ticket.email);
const customerPhone = firstMeaningful(original.customer_phone, lead.phone, ticket.phone);
const notificationContactLine = [customerName, customerEmail, customerPhone].filter(Boolean).join(' | ') || 'Contact not provided';
const notificationSubjectLabel = firstMeaningful(ticket.summary, lead.items_needed, original.intent, 'Support update');
const missingFieldsText = firstMeaningful(original.missing_fields_text, Array.isArray(original.missing_fields) ? original.missing_fields.join(', ') : '', 'none');
const safeConversationTranscriptHtml = transcriptHtml + truncationHtml;
const notificationSummaryHtml = [
  '<table cellpadding="6" cellspacing="0" style="border-collapse:collapse;width:100%;max-width:760px;">',
  '<tr><td style="width:150px;color:#52606d;"><strong>Conversation</strong></td><td>' + escapeHtml(conversationRef) + '</td></tr>',
  '<tr><td style="color:#52606d;"><strong>Case</strong></td><td>' + escapeHtml(caseReference) + '</td></tr>',
  '<tr><td style="color:#52606d;"><strong>Session</strong></td><td>' + escapeHtml(original.session_id || '') + '</td></tr>',
  '<tr><td style="color:#52606d;"><strong>Contact</strong></td><td>' + escapeHtml(notificationContactLine) + '</td></tr>',
  '<tr><td style="color:#52606d;"><strong>Intent</strong></td><td>' + escapeHtml(original.intent || '') + '</td></tr>',
  '<tr><td style="color:#52606d;"><strong>Escalation</strong></td><td>' + escapeHtml(boolText(original.needs_escalation || original.incomplete_ticket_followup)) + '</td></tr>',
  '<tr><td style="color:#52606d;"><strong>Missing fields</strong></td><td>' + escapeHtml(missingFieldsText) + '</td></tr>',
  '<tr><td style="color:#52606d;"><strong>Completed</strong></td><td>' + escapeHtml(original.completed_at || '') + '</td></tr>',
  '</table>',
].join('');

return [{
  json: {
    ...original,
    customer_name: customerName,
    customer_email: customerEmail,
    customer_phone: customerPhone,
    conversation_ref: conversationRef,
    conversation_transcript_text: transcriptText + truncationText,
    conversation_transcript_html: safeConversationTranscriptHtml,
    notification_contact_line: notificationContactLine,
    notification_subject_label: notificationSubjectLabel,
    notification_summary_html: notificationSummaryHtml,
    conversation_message_count: transcriptSourceRows.length,
    conversation_transcript_rows_rendered: selectedEntries.length,
    transcript_truncated: transcriptTruncated,
    subject_escalation_intent: safeSubjectText(original.intent, 'Support alert'),
    subject_escalation_reference: safeSubjectText(firstMeaningful(original.escalation_reference_id, caseReference, conversationRef), '__SET_BUILD_INTERNAL_ERROR_CONTEXT_EXECUTION_URL__'),
    subject_lead_name: safeSubjectText(firstMeaningful(lead.name, customerName, 'New enquiry'), 'New enquiry'),
    subject_lead_items: safeSubjectText(firstMeaningful(lead.items_needed, lead.rental_purpose, original.lead_id, 'Rental enquiry'), 'Rental enquiry'),
    subject_lead_reference: safeSubjectText(firstMeaningful(original.lead_id, conversationRef), '__SET_BUILD_INTERNAL_ERROR_CONTEXT_EXECUTION_URL__'),
    subject_ticket_urgency: safeSubjectText(firstMeaningful(ticket.urgency, 'medium'), 'medium'),
    subject_ticket_summary: safeSubjectText(firstMeaningful(ticket.summary, original.ticket_id, 'Support ticket'), 'Support ticket'),
    subject_ticket_reference: safeSubjectText(firstMeaningful(original.ticket_id, conversationRef), '__SET_BUILD_INTERNAL_ERROR_CONTEXT_EXECUTION_URL__'),
    subject_unanswered_intent: safeSubjectText(original.intent, 'Unanswered'),
    subject_unanswered_reference: safeSubjectText(firstMeaningful(original.unanswered_id, conversationRef), '__SET_BUILD_INTERNAL_ERROR_CONTEXT_EXECUTION_URL__'),
    safe_conversation_ref: safeText(conversationRef),
    safe_case_reference: safeText(caseReference),
    safe_session_id: safeText(original.session_id),
    safe_customer_name: safeText(customerName),
    safe_customer_email: safeText(customerEmail),
    safe_customer_phone: safeText(customerPhone),
    safe_notification_contact_line: safeText(notificationContactLine),
    safe_notification_subject_label: safeText(notificationSubjectLabel),
